export default {
  name: 'testComponent',
  data: function data() {
    return {
      day: '0',
      hour: '0',
      minute: '0',
      second: '0'
    };
  },
  props: {
    dateNumber: {
      type: String,
      default: new Date().getTime()
    }
  },
  methods: {
    countTime: function countTime() {
      var nowDate = new Date();
      var endDate = new Date(this.dateNumber);
      var date = endDate - nowDate;

      if (date > 0) {
        this.day = this.checkedZero(Math.floor(date / 1000 / 60 / 60 / 24));
        this.hour = this.checkedZero(Math.floor(date / 1000 / 60 / 60 % 24));
        this.minute = this.checkedZero(Math.floor(date / 1000 / 60 % 60));
        this.second = this.checkedZero(Math.floor(date / 1000 % 60));
      } // console.log(this.day, this.hour, this.minute, this.second);


      setTimeout(this.countTime, 1000);
    },
    checkedZero: function checkedZero(number) {
      if (number < 9) {
        // eslint-disable-next-line no-param-reassign
        number = "0".concat(number);
      }

      return number;
    }
  },
  mounted: function mounted() {
    this.countTime();
  }
};